+ function deepClone(obj) {
+   if (Array.isArray(obj)) return obj.map(deepClone);
+   if (obj !== null && typeof obj === 'object') {
+     const out = {}; for (const k in obj) out[k] = deepClone(obj[k]); return out;
+   }
+   return obj;
+ }

